 95→type CompactorMetrics struct {
 96→	Ran               prometheus.Counter
 97→	PopulatingBlocks  prometheus.Gauge
 98→	OverlappingBlocks prometheus.Counter
 99→	Duration          prometheus.Histogram
100→	ChunkSize         prometheus.Histogram
101→	ChunkSamples      prometheus.Histogram
102→	ChunkRange        prometheus.Histogram
103→}
104→
105→// NewCompactorMetrics initializes metrics for Compactor.
106→func NewCompactorMetrics(r prometheus.Registerer) *CompactorMetrics {
107→	m := &CompactorMetrics{}
108→
109→	m.Ran = prometheus.NewCounter(prometheus.CounterOpts{
110→		Name: "prometheus_tsdb_compactions_total",
111→		Help: "Total number of compactions that were executed for the partition.",
112→	})
113→	m.PopulatingBlocks = prometheus.NewGauge(prometheus.GaugeOpts{
114→		Name: "prometheus_tsdb_compaction_populating_block",
115→		Help: "Set to 1 when a block is currently being written to the disk.",
116→	})
117→	m.OverlappingBlocks = prometheus.NewCounter(prometheus.CounterOpts{
118→		Name: "prometheus_tsdb_vertical_compactions_total",
119→		Help: "Total number of compactions done on overlapping blocks.",
120→	})
121→	m.Duration = prometheus.NewHistogram(prometheus.HistogramOpts{
122→		Name:                            "prometheus_tsdb_compaction_duration_seconds",
123→		Help:                            "Duration of compaction runs",
124→		Buckets:                         prometheus.ExponentialBuckets(1, 2, 14),
125→		NativeHistogramBucketFactor:     1.1,
126→		NativeHistogramMaxBucketNumber:  100,
127→		NativeHistogramMinResetDuration: 1 * time.Hour,
128→	})
129→	m.ChunkSize = prometheus.NewHistogram(prometheus.HistogramOpts{
130→		Name:    "prometheus_tsdb_compaction_chunk_size_bytes",
131→		Help:    "Final size of chunks on their first compaction",
132→		Buckets: prometheus.ExponentialBuckets(32, 1.5, 12),
133→	})
134→	m.ChunkSamples = prometheus.NewHistogram(prometheus.HistogramOpts{
135→		Name:    "prometheus_tsdb_compaction_chunk_samples",
136→		Help:    "Final number of samples on their first compaction",
137→		Buckets: prometheus.ExponentialBuckets(4, 1.5, 12),
138→	})
139→	m.ChunkRange = prometheus.NewHistogram(prometheus.HistogramOpts{
140→		Name:    "prometheus_tsdb_compaction_chunk_range_seconds",
141→		Help:    "Final time range of chunks on their first compaction",
142→		Buckets: prometheus.ExponentialBuckets(100, 4, 10),
143→	})
144→
145→	if r != nil {
146→		r.MustRegister(
147→			m.Ran,
148→			m.PopulatingBlocks,
149→			m.OverlappingBlocks,
150→			m.Duration,
151→			m.ChunkRange,
152→			m.ChunkSamples,
153→			m.ChunkSize,
154→		)
155→	}
156→	return m
157→}
