483→// Compact creates a new block in the compactor's directory from the blocks in the
484→// provided directories.
485→func (c *LeveledCompactor) Compact(dest string, dirs []string, open []*Block) ([]ulid.ULID, error) {
486→	return c.CompactWithBlockPopulator(dest, dirs, open, DefaultBlockPopulator{})
487→}
488→
489→func (c *LeveledCompactor) CompactWithBlockPopulator(dest string, dirs []string, open []*Block, blockPopulator BlockPopulator) ([]ulid.ULID, error) {
490→	var (
491→		blocks []BlockReader
492→		bs     []*Block
493→		metas  []*BlockMeta
494→		uids   []string
495→	)
496→	start := time.Now()
497→
498→	for _, d := range dirs {
499→		select {
500→		case <-c.ctx.Done():
501→			return nil, c.ctx.Err()
502→		default:
503→		}
504→
505→		meta, _, err := readMetaFile(d)
506→		if err != nil {
507→			return nil, err
508→		}
509→
510→		var b *Block
511→
512→		// Use already open blocks if we can, to avoid
513→		// having the index data in memory twice.
514→		for _, o := range open {
515→			if meta.ULID == o.Meta().ULID {
516→				b = o
517→				break
518→			}
519→		}
520→
521→		if b == nil {
522→			var err error
523→			b, err = OpenBlock(c.logger, d, c.chunkPool, c.postingsDecoderFactory)
524→			if err != nil {
525→				return nil, err
526→			}
527→			defer b.Close()
528→		}
529→
530→		metas = append(metas, meta)
531→		blocks = append(blocks, b)
532→		bs = append(bs, b)
533→		uids = append(uids, meta.ULID.String())
534→	}
535→
536→	uid := ulid.MustNew(ulid.Now(), rand.Reader)
537→
538→	meta := CompactBlockMetas(uid, metas...)
539→	err := c.write(dest, meta, blockPopulator, blocks...)
540→	if err == nil {
541→		if meta.Stats.NumSamples == 0 {
542→			for _, b := range bs {
543→				b.meta.Compaction.Deletable = true
544→				n, err := writeMetaFile(c.logger, b.dir, &b.meta)
545→				if err != nil {
546→					c.logger.Error(
547→						"Failed to write 'Deletable' to meta file after compaction",
548→						"ulid", b.meta.ULID,
549→					)
550→				}
551→				b.numBytesMeta = n
552→			}
553→			c.logger.Info(
554→				"compact blocks resulted in empty block",
555→				"count", len(blocks),
556→				"sources", fmt.Sprintf("%v", uids),
557→				"duration", time.Since(start),
558→			)
559→			return nil, nil
560→		}
561→
562→		c.logger.Info(
563→			"compact blocks",
564→			"count", len(blocks),
565→			"mint", meta.MinTime,
566→			"maxt", meta.MaxTime,
567→			"ulid", meta.ULID,
568→			"sources", fmt.Sprintf("%v", uids),
569→			"duration", time.Since(start),
570→		)
571→		return []ulid.ULID{uid}, nil
572→	}
573→
574→	errs := []error{err}
575→	if !errors.Is(err, context.Canceled) {
576→		for _, b := range bs {
577→			if err := b.setCompactionFailed(); err != nil {
578→				errs = append(errs, fmt.Errorf("setting compaction failed for block: %s: %w", b.Dir(), err))
579→			}
580→		}
581→	}
582→
583→	return nil, errors.Join(errs...)
584→}
585→
586→func (c *LeveledCompactor) Write(dest string, b BlockReader, mint, maxt int64, base *BlockMeta) ([]ulid.ULID, error) {
587→	start := time.Now()
588→
589→	uid := ulid.MustNew(ulid.Now(), rand.Reader)
590→	c.logger.Info("write block started", "mint", mint, "maxt", maxt, "ulid", uid)
591→
592→	meta := &BlockMeta{
593→		ULID:    uid,
594→		MinTime: mint,
595→		MaxTime: maxt,
596→	}
597→	meta.Compaction.Level = 1
598→	meta.Compaction.Sources = []ulid.ULID{uid}
599→
600→	if base != nil {
601→		meta.Compaction.Parents = []BlockDesc{
602→			{ULID: base.ULID, MinTime: base.MinTime, MaxTime: base.MaxTime},
603→		}
604→		if base.Compaction.FromOutOfOrder() {
605→			meta.Compaction.SetOutOfOrder()
606→		}
607→		if base.Compaction.FromStaleSeries() {
608→			meta.Compaction.SetStaleSeries()
609→		}
610→	}
611→
612→	err := c.write(dest, meta, DefaultBlockPopulator{}, b)
613→	if err != nil {
614→		return nil, err
615→	}
616→
617→	if meta.Stats.NumSamples == 0 {
618→		c.logger.Info(
619→			"write block resulted in empty block",
620→			"mint", meta.MinTime,
621→			"maxt", meta.MaxTime,
622→			"duration", time.Since(start),
623→		)
624→		return nil, nil
625→	}
626→
627→	c.logger.Info(
628→		"write block completed",
629→		"mint", meta.MinTime,
630→		"maxt", meta.MaxTime,
631→		"ulid", meta.ULID,
632→		"duration", time.Since(start),
633→		"ooo", meta.Compaction.FromOutOfOrder(),
634→	)
635→	return []ulid.ULID{uid}, nil
636→}
