1406→func (db *DB) waitingForCompactionDelay() bool {
1407→	return time.Since(db.timeWhenCompactionDelayStarted) < db.opts.CompactionDelay
1408→}
1409→
1410→// Compact data if possible. After successful compaction blocks are reloaded
1411→// which will also delete the blocks that fall out of the retention window.
1412→// Old blocks are only deleted on reloadBlocks based on the new block's parent information.
1413→// See DB.reloadBlocks documentation for further information.
1414→func (db *DB) Compact(ctx context.Context) (returnErr error) {
1415→	db.cmtx.Lock()
1416→	defer db.cmtx.Unlock()
1417→	defer func() {
1418→		if returnErr != nil && !errors.Is(returnErr, context.Canceled) {
1419→			// If we got an error because context was canceled then we're most likely
1420→			// shutting down TSDB and we don't need to report this on metrics
1421→			db.metrics.compactionsFailed.Inc()
1422→		}
1423→	}()
1424→
1425→	lastBlockMaxt := int64(math.MinInt64)
1426→	defer func() {
1427→		if err := db.head.truncateWAL(lastBlockMaxt); err != nil {
1428→			returnErr = errors.Join(returnErr, fmt.Errorf("WAL truncation in Compact defer: %w", err))
1429→		}
1430→	}()
1431→
1432→	start := time.Now()
1433→	// Check whether we have pending head blocks that are ready to be persisted.
1434→	// They have the highest priority.
1435→	for {
1436→		select {
1437→		case <-db.stopc:
1438→			return nil
1439→		default:
1440→		}
1441→
1442→		if !db.head.compactable() {
1443→			// Reset the counter once the head compactions are done.
1444→			// This would also reset it if a manual compaction was triggered while the auto compaction was in its delay period.
1445→			if !db.timeWhenCompactionDelayStarted.IsZero() {
1446→				db.timeWhenCompactionDelayStarted = time.Time{}
1447→			}
1448→			break
1449→		}
1450→
1451→		if db.timeWhenCompactionDelayStarted.IsZero() {
1452→			// Start counting for the delay.
1453→			db.timeWhenCompactionDelayStarted = time.Now()
1454→		}
1455→		if db.waitingForCompactionDelay() {
1456→			break
1457→		}
1458→		mint := db.head.MinTime()
1459→		maxt := rangeForTimestamp(mint, db.head.chunkRange.Load())
1460→
1461→		// Wrap head into a range that bounds all reads to it.
1462→		// We remove 1 millisecond from maxt because block
1463→		// intervals are half-open: [b.MinTime, b.MaxTime). But
1464→		// chunk intervals are closed: [c.MinTime, c.MaxTime];
1465→		// so in order to make sure that overlaps are evaluated
1466→		// consistently, we explicitly remove the last value
1467→		// from the block interval here.
1468→		rh := NewRangeHeadWithIsolationDisabled(db.head, mint, maxt-1)
1469→
1470→		// Compaction runs with isolation disabled, because head.compactable()
1471→		// ensures that maxt is more than chunkRange/2 back from now, and
1472→		// head.appendableMinValidTime() ensures that no new appends can start within the compaction range.
1473→		// We do need to wait for any overlapping appenders that started previously to finish.
1474→		db.head.WaitForAppendersOverlapping(rh.MaxTime())
1475→
1476→		if err := db.compactHead(rh); err != nil {
1477→			return fmt.Errorf("compact head: %w", err)
1478→		}
1479→		// Consider only successful compactions for WAL truncation.
1480→		lastBlockMaxt = maxt
1481→	}
1482→
1483→	// Clear some disk space before compacting blocks, especially important
1484→	// when Head compaction happened over a long time range.
1485→	if err := db.head.truncateWAL(lastBlockMaxt); err != nil {
1486→		return fmt.Errorf("WAL truncation in Compact: %w", err)
1487→	}
1488→
1489→	compactionDuration := time.Since(start)
1490→	if compactionDuration.Milliseconds() > db.head.chunkRange.Load() {
1491→		db.logger.Warn(
1492→			"Head compaction took longer than the block time range, compactions are falling behind and won't be able to catch up",
1493→			"duration", compactionDuration.String(),
1494→			"block_range", db.head.chunkRange.Load(),
1495→		)
1496→	}
1497→
1498→	if lastBlockMaxt != math.MinInt64 {
1499→		// The head was compacted, so we compact OOO head as well.
1500→		if err := db.compactOOOHead(ctx); err != nil {
1501→			return fmt.Errorf("compact ooo head: %w", err)
1502→		}
1503→	}
1504→
1505→	return db.compactBlocks()
1506→}
