1510→	db.cmtx.Lock()
1511→	defer db.cmtx.Unlock()
1512→
1513→	if err := db.compactHead(head); err != nil {
1514→		return fmt.Errorf("compact head: %w", err)
1515→	}
1516→
1517→	if err := db.head.truncateWAL(head.BlockMaxTime()); err != nil {
1518→		return fmt.Errorf("WAL truncation: %w", err)
1519→	}
