1523→// CompactOOOHead compacts the OOO Head.
1524→func (db *DB) CompactOOOHead(ctx context.Context) error {
1525→	db.cmtx.Lock()
1526→	defer db.cmtx.Unlock()
1527→
1528→	return db.compactOOOHead(ctx)
1529→}
1530→
1531→// Callback for testing.
1532→var compactOOOHeadTestingCallback func()
1533→
1534→// The db.cmtx mutex should be held before calling this method.
1535→func (db *DB) compactOOOHead(ctx context.Context) error {
1536→	if !db.oooWasEnabled.Load() {
1537→		return nil
1538→	}
1539→	oooHead, err := NewOOOCompactionHead(ctx, db.head)
1540→	if err != nil {
1541→		return fmt.Errorf("get ooo compaction head: %w", err)
1542→	}
1543→
1544→	if compactOOOHeadTestingCallback != nil {
1545→		compactOOOHeadTestingCallback()
1546→		compactOOOHeadTestingCallback = nil
1547→	}
1548→
1549→	ulids, err := db.compactOOO(db.dir, oooHead)
1550→	if err != nil {
1551→		return fmt.Errorf("compact ooo head: %w", err)
1552→	}
1553→	if err := db.reloadBlocks(); err != nil {
1554→		errs := []error{err}
1555→		for _, uid := range ulids {
1556→			if errRemoveAll := os.RemoveAll(filepath.Join(db.dir, uid.String())); errRemoveAll != nil {
1557→				errs = append(errs, errRemoveAll)
1558→			}
1559→		}
1560→		return fmt.Errorf("reloadBlocks blocks after failed compact ooo head: %w", errors.Join(errs...))
1561→	}
1562→
1563→	lastWBLFile, minOOOMmapRef := oooHead.LastWBLFile(), oooHead.LastMmapRef()
1564→	if lastWBLFile != 0 || minOOOMmapRef != 0 {
1565→		if minOOOMmapRef != 0 {
1566→			// Ensure that no more queriers are created that will reference chunks we're about to garbage collect.
1567→			// truncateOOO waits for any existing queriers that reference chunks we're about to garbage collect to
1568→			// complete before running garbage collection, so we don't need to do that here.
1569→			//
1570→			// We take mtx to ensure that Querier() and ChunkQuerier() don't miss blocks: without this, they could
1571→			// capture the list of blocks before the call to reloadBlocks() above runs, but then capture
1572→			// lastGarbageCollectedMmapRef after we update it here, and therefore not query either the blocks we've just
1573→			// written or the head chunks those blocks were created from.
1574→			db.mtx.Lock()
1575→			db.lastGarbageCollectedMmapRef = minOOOMmapRef
1576→			db.mtx.Unlock()
1577→		}
1578→
1579→		if err := db.head.truncateOOO(lastWBLFile, minOOOMmapRef); err != nil {
1580→			return fmt.Errorf("truncate ooo wbl: %w", err)
1581→		}
1582→	}
1583→
1584→	return nil
1585→}
