1587→// compactOOO creates a new block per possible block range in the compactor's directory from the OOO Head given.
1588→// Each ULID in the result corresponds to a block in a unique time range.
1589→// The db.cmtx mutex should be held before calling this method.
1590→func (db *DB) compactOOO(dest string, oooHead *OOOCompactionHead) (_ []ulid.ULID, err error) {
1591→	db.logger.Info("out-of-order compaction started")
1592→	start := time.Now()
1593→
1594→	blockSize := oooHead.ChunkRange()
1595→	oooHeadMint, oooHeadMaxt := oooHead.MinTime(), oooHead.MaxTime()
1596→	ulids := make([]ulid.ULID, 0)
1597→	defer func() {
1598→		if err != nil {
1599→			// Best effort removal of created block on any error.
1600→			for _, uid := range ulids {
1601→				_ = os.RemoveAll(filepath.Join(db.dir, uid.String()))
1602→			}
1603→		}
1604→	}()
1605→
1606→	meta := &BlockMeta{}
1607→	meta.Compaction.SetOutOfOrder()
1608→	for t := blockSize * (oooHeadMint / blockSize); t <= oooHeadMaxt; t += blockSize {
1609→		mint, maxt := t, t+blockSize
1610→		// Block intervals are half-open: [b.MinTime, b.MaxTime). Block intervals are always +1 than the total samples it includes.
1611→		uids, err := db.compactor.Write(dest, oooHead.CloneForTimeRange(mint, maxt-1), mint, maxt, meta)
1612→		if err != nil {
1613→			return nil, err
1614→		}
1615→		ulids = append(ulids, uids...)
1616→	}
1617→
1618→	if len(ulids) == 0 {
1619→		db.logger.Info(
1620→			"compact ooo head resulted in no blocks",
1621→			"duration", time.Since(start),
1622→		)
1623→		return nil, nil
1624→	}
1625→
1626→	db.logger.Info(
1627→		"out-of-order compaction completed",
1628→		"duration", time.Since(start),
1629→		"ulids", fmt.Sprintf("%v", ulids),
1630→	)
1631→	return ulids, nil
1632→}
