1792→// reloadBlocks reloads blocks without touching head.
1793→// Blocks that are obsolete due to replacement or retention will be deleted.
1794→// The db.cmtx mutex should be held before calling this method.
1795→func (db *DB) reloadBlocks() (err error) {
1796→	defer func() {
1797→		if err != nil {
1798→			db.metrics.reloadsFailed.Inc()
1799→		}
1800→		db.metrics.reloads.Inc()
1801→	}()
1802→
1803→	db.mtx.RLock()
1804→	loadable, corrupted, err := openBlocks(db.logger, db.dir, db.blocks, db.chunkPool, db.opts.PostingsDecoderFactory)
1805→	db.mtx.RUnlock()
1806→	if err != nil {
1807→		return err
1808→	}
1809→
1810→	deletableULIDs := db.blocksToDelete(loadable)
1811→	deletable := make(map[ulid.ULID]*Block, len(deletableULIDs))
1812→
1813→	// Mark all parents of loaded blocks as deletable (no matter if they exists). This makes it resilient against the process
1814→	// crashing towards the end of a compaction but before deletions. By doing that, we can pick up the deletion where it left off during a crash.
1815→	for _, block := range loadable {
1816→		if _, ok := deletableULIDs[block.meta.ULID]; ok {
1817→			deletable[block.meta.ULID] = block
1818→		}
1819→		for _, b := range block.Meta().Compaction.Parents {
1820→			if _, ok := corrupted[b.ULID]; ok {
1821→				delete(corrupted, b.ULID)
1822→				db.logger.Warn("Found corrupted block, but replaced by compacted one so it's safe to delete. This should not happen with atomic deletes.", "block", b.ULID)
1823→			}
1824→			deletable[b.ULID] = nil
1825→		}
1826→	}
1827→
1828→	if len(corrupted) > 0 {
1829→		// Corrupted but no child loaded for it.
1830→		// Close all new blocks to release the lock for windows.
1831→		db.mtx.RLock()
1832→		for _, block := range loadable {
1833→			if _, open := getBlock(db.blocks, block.Meta().ULID); !open {
1834→				block.Close()
1835→			}
1836→		}
1837→		db.mtx.RUnlock()
1838→		var errs []error
1839→		for ulid, err := range corrupted {
1840→			if err != nil {
1841→				errs = append(errs, fmt.Errorf("corrupted block %s: %w", ulid.String(), err))
1842→			}
1843→		}
1844→		return errors.Join(errs...)
1845→	}
1846→
1847→	var (
1848→		toLoad     []*Block
1849→		blocksSize int64
1850→	)
1851→	// All deletable blocks should be unloaded.
1852→	// NOTE: We need to loop through loadable one more time as there might be loadable ready to be removed (replaced by compacted block).
1853→	for _, block := range loadable {
1854→		if _, ok := deletable[block.Meta().ULID]; ok {
1855→			deletable[block.Meta().ULID] = block
1856→			continue
1857→		}
1858→
1859→		toLoad = append(toLoad, block)
1860→		blocksSize += block.Size()
1861→	}
1862→	db.metrics.blocksBytes.Set(float64(blocksSize))
1863→
1864→	slices.SortFunc(toLoad, func(a, b *Block) int {
1865→		switch {
1866→		case a.Meta().MinTime < b.Meta().MinTime:
1867→			return -1
1868→		case a.Meta().MinTime > b.Meta().MinTime:
1869→			return 1
1870→		default:
1871→			return 0
1872→		}
1873→	})
1874→
1875→	// Swap new blocks first for subsequently created readers to be seen.
1876→	db.mtx.Lock()
1877→	oldBlocks := db.blocks
1878→	db.blocks = toLoad
1879→	db.mtx.Unlock()
1880→
1881→	// Only check overlapping blocks when overlapping compaction is enabled.
1882→	if db.opts.EnableOverlappingCompaction {
1883→		blockMetas := make([]BlockMeta, 0, len(toLoad))
1884→		for _, b := range toLoad {
1885→			blockMetas = append(blockMetas, b.Meta())
1886→		}
1887→		if overlaps := OverlappingBlocks(blockMetas); len(overlaps) > 0 {
1888→			db.logger.Warn("Overlapping blocks found during reloadBlocks", "detail", overlaps.String())
1889→		}
1890→	}
1891→
1892→	// Append blocks to old, deletable blocks, so we can close them.
1893→	for _, b := range oldBlocks {
1894→		if _, ok := deletable[b.Meta().ULID]; ok {
1895→			deletable[b.Meta().ULID] = b
1896→		}
1897→	}
1898→	if err := db.deleteBlocks(deletable); err != nil {
1899→		return fmt.Errorf("delete %v blocks: %w", len(deletable), err)
1900→	}
1901→	return nil
1902→}
