 32→type mergeGenericQuerier struct {
 33→	queriers []genericQuerier
 34→
 35→	// mergeFn is used when we see series from different queriers Selects with the same labels.
 36→	mergeFn genericSeriesMergeFunc
 37→
 38→	// TODO(bwplotka): Remove once remote queries are asynchronous. False by default.
