		if len(plan) == 0 {
			break  // No blocks to compact
		}

		select {
		case <-db.stopc:
			return nil
		default:
		}

		// STEP 2: Compact - Execute compaction on planned blocks
		uids, err := db.compactor.Compact(db.dir, plan, db.blocks)
		if err != nil {
